# REMOVE
--------------------------------------------------------------*/
satus.storage.remove = function (key, callback) {
	var target = this.data;

	if (typeof key !== 'string') {
		return;
	}

	key = key.split('/').filter(function (value) {
		return value != '';
	});

	for (var i = 0, l = key.length; i < l; i++) {
		if (satus.isset(target[key[i]])) {
			if (i === l - 1) {
				delete target[key[i]];
			} else {
				target = target[key[i]];
			}
		} else {
