const fs = require('fs');
const vm = require('vm');
const path = require('path');

describe('YouTube theme switching', () => {
  let context;
  let documentElement;
  let masthead;
  let cinematics;
  let appendedStyles;

  beforeEach(() => {
    appendedStyles = [];

    documentElement = {
      attributes: {},
      setAttribute: jest.fn(function (name, value) {
        this.attributes[name] = value;
      }),
      removeAttribute: jest.fn(function (name) {
        delete this.attributes[name];
      }),
      hasAttribute: jest.fn(function (name) {
        return Object.prototype.hasOwnProperty.call(this.attributes, name);
      }),
      appendChild: jest.fn(function (element) {
        appendedStyles.push(element);
      })
    };

    masthead = {
      attributes: {},
      setAttribute: jest.fn(function (name, value) {
        this.attributes[name] = value;
      }),
      removeAttribute: jest.fn(function (name) {
        delete this.attributes[name];
      })
    };

    cinematics = {
      style: {
        values: {},
        setProperty: jest.fn(function (name, value) {
          this.values[name] = value;
        })
      },
      removeAttribute: jest.fn(function (name) {
        if (name === 'style') {
          this.style.values = {};
        }
      })
    };

    context = {
      ImprovedTube: {
        storage: {},
        elements: {},
        messages: {
          send: jest.fn(function (message) {
            if (message.action === 'set' && message.key === 'theme') {
              if (message.value) {
                context.ImprovedTube.storage.theme = message.value;
              } else {
                delete context.ImprovedTube.storage.theme;
              }
            }
          })
        },
        setPrefCookieValueByName: jest.fn()
      },
      document: {
        documentElement,
        createElement: jest.fn(() => ({ remove: jest.fn() })),
        querySelector: jest.fn((selector) => selector === 'ytd-masthead' ? masthead : null),
        getElementById: jest.fn((id) => id === 'cinematics' ? cinematics : null)
      }
    };

    vm.createContext(context);
    vm.runInContext(
      fs.readFileSync(path.join(__dirname, '../../js&css/web-accessible/www.youtube.com/themes.js'), 'utf8'),
      context
    );
  });

  test('removes YouTube dark attributes when switching from YouTube Dark to YouTube Light', () => {
    context.ImprovedTube.storage.theme = 'dark';
    context.ImprovedTube.setTheme();

    expect(documentElement.hasAttribute('dark')).toBe(true);
    expect(masthead.attributes).toHaveProperty('dark');

    context.ImprovedTube.storage.theme = 'light';
    context.ImprovedTube.setTheme();

    expect(documentElement.hasAttribute('dark')).toBe(false);
    expect(masthead.attributes).not.toHaveProperty('dark');
    expect(context.ImprovedTube.setPrefCookieValueByName).toHaveBeenLastCalledWith('f6', null);
  });
});

