const fs = require('fs');
const vm = require('vm');
const path = require('path');

describe('Themes panel YouTube Light option', () => {
  let context;
  let themeSection;

  beforeEach(() => {
    context = {
      extension: {
        skeleton: {
          main: {
            layers: {
              section: {}
            }
          }
        }
      },
      satus: {
        storage: {
          data: {},
          get: jest.fn(function (key) {
            return this.data[key];
          })
        }
      }
    };

    vm.createContext(context);
    vm.runInContext(
      fs.readFileSync(path.join(__dirname, '../../menu/skeleton-parts/themes.js'), 'utf8'),
      context
    );

    themeSection = context.extension.skeleton.main.layers.section.themes.on.click.section;
  });

  test('uses stored dark theme as the checked default so YouTube Light is saved when selected after YouTube Dark', () => {
    context.satus.storage.data.theme = 'dark';

    const darkOption = themeSection.default();
    const lightOption = themeSection.opposite();

    expect(darkOption.text).toBe('youtubesDark');
    expect(darkOption.radio.value).toBe('dark');
    expect(darkOption.radio.checked).toBe(true);
    expect(lightOption.text).toBe('youtubesLight');
    expect(lightOption.radio.value).toBe('light');
    expect(lightOption.radio.checked).toBeUndefined();
  });
});

